import { ok } from '@agentcash/neverthrow';

import { getEvmWallet } from './evm';
import { getSvmWallet } from './svm';

import type { OkValue } from '@agentcash/neverthrow/types';

export const getWallet = async () => {
  const [evmWallet, svmWallet] = await Promise.all([
    getEvmWallet(),
    getSvmWallet(),
  ]);

  if (evmWallet.isErr()) {
    return evmWallet;
  }

  if (svmWallet.isErr()) {
    return svmWallet;
  }

  return ok({
    evm: evmWallet.value,
    svm: svmWallet.value,
  });
};

export type Wallets = OkValue<Awaited<ReturnType<typeof getWallet>>>;
