import { existsSync } from 'fs';

import {
  createKeyPairSignerFromBytes,
  isAddress,
  createKeyPairSignerFromPrivateKeyBytes,
} from '@solana/kit';

import { getRandomValues } from 'crypto';

import { base58 } from '@scure/base';

import z from 'zod';

import { ok } from '@agentcash/neverthrow';

import {
  fsErr,
  safeChmod,
  safeReadFile,
  safeWriteFile,
} from '@/shared/neverthrow/fs';
import { jsonErr, safeParseJson } from '@/shared/neverthrow/json';
import { safeParse } from '@/shared/neverthrow/parse';

import { log } from '../shared/log';
import { configFile } from '../shared/fs';

const WALLET_FILE = configFile('solana-wallet.json');

const storedWalletSchema = z.object({
  privateKey: z
    .string()
    .regex(/^[1-9A-HJ-NP-Za-km-z]+$/, 'Invalid base58 string'),
  address: z.string().refine(isAddress, 'Invalid Solana address'),
  createdAt: z.string(),
});

const walletSurface = 'wallet';

export async function getSvmWallet() {
  if (process.env.X402_SOLANA_PRIVATE_KEY) {
    const account = await createKeyPairSignerFromBytes(
      base58.decode(process.env.X402_SOLANA_PRIVATE_KEY)
    );
    log.info(`Using wallet from env: ${account.address}`);
    return ok(account);
  }

  const readFileResult = await safeReadFile(walletSurface, WALLET_FILE);

  if (!readFileResult.isOk()) {
    const fileExistsResult = existsSync(WALLET_FILE);
    // file exists but is not readable
    if (fileExistsResult) {
      return fsErr(walletSurface, {
        cause: 'file_not_readable',
        message: `The file exists but is not readable. Fix corrupted state file: ${WALLET_FILE}`,
      });
    }
  }

  if (readFileResult.isOk()) {
    const data = readFileResult.value;
    const jsonParseResult = safeParseJson(walletSurface, data);

    // file exists but is not valid JSON
    if (jsonParseResult.isErr()) {
      return jsonErr(walletSurface, {
        cause: 'parse',
        message: `The data in ${WALLET_FILE} is not valid JSON`,
      });
    }

    const parseResult = safeParse(
      walletSurface,
      storedWalletSchema,
      jsonParseResult.value
    );

    // file has valid JSON but is not a valid wallet configuration
    if (parseResult.isErr()) {
      return parseResult;
    }

    const account = await createKeyPairSignerFromPrivateKeyBytes(
      base58.decode(parseResult.value.privateKey)
    );
    log.info(`Loaded wallet: ${account.address}`);
    return ok(account);
  }

  // Generate new
  const privateKeyBytes = getRandomValues(new Uint8Array(32));
  const account = await createKeyPairSignerFromPrivateKeyBytes(privateKeyBytes);
  const stored = {
    privateKey: base58.encode(privateKeyBytes),
    address: account.address,
    createdAt: new Date().toISOString(),
  };

  const saveResult = await safeWriteFile(
    walletSurface,
    WALLET_FILE,
    JSON.stringify(stored, null, 2)
  ).andThen(() => safeChmod(walletSurface, WALLET_FILE, 0o600));

  if (saveResult.isErr()) {
    return saveResult;
  }

  log.info(`Created wallet: ${account.address}`);
  log.info(`Saved to: ${WALLET_FILE}`);

  return ok(account);
}
